package JavaPractice;

public class ElseIfCondition1 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
     if(20 > 18) {
    	 System.out.println("20 is greater than 18");
     }
     else if(20 > 18) {
    	 System.out.println("20 is lesse than 18");
    	 
     }
     else if(20 == 18) {
    	 System.out.println("20 is greater than 18"); 
     }
     else {
    	 System.out.println("20 is lesser than 18");
     }
	}

}
